import React, { useState, useMemo } from "react";
import EditorialFlow from "./EditorialFlow";
import { ImportModal } from './modals'; // ✅ Import de la modale séparée

interface MediaLibraryProps {
  onBack?: () => void;
}

const MediaLibrary: React.FC<MediaLibraryProps> = ({ onBack }) => {
  const [view, setView] = useState<'library' | 'flow'>('library');
  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const [importType, setImportType] = useState<'raw' | 'transcription' | 'book' | 'proofreading1' | 'proofreading2' | null>(null);
  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [isUploading, setIsUploading] = useState(false);

  return (
    <div className="container mx-auto px-4 py-4 h-full flex flex-col">
      {/* Bouton Retour */}
      {onBack && (
        <button
          onClick={onBack}
          className="mb-4 px-4 py-2 bg-gray-200 dark:bg-gray-700 hover:bg-gray-300 dark:hover:bg-gray-600 rounded-lg text-sm transition-all duration-200 flex items-center gap-2 w-fit"
        >
          <i className="fas fa-arrow-left"></i>
          Retour aux Documents
        </button>
      )}

      {/* En-tête avec Stats */}
      <div className="bg-gradient-to-r from-purple-600 to-indigo-600 rounded-xl shadow-lg mb-4 p-6 text-white">
        <div className="flex flex-col lg:flex-row lg:items-center lg:justify-between gap-4">
          <div>
            <h1 className="text-3xl font-bold flex items-center gap-3">
              <i className="fas fa-folder-open"></i>
              Médiathèque BCM-GEST
            </h1>
            <p className="text-purple-100 mt-2">
              Gérez vos fichiers bruts, transcriptions, projets et relectures
            </p>
          </div>
          
          {/* Stats Rapides */}
          <div className="flex gap-4 flex-wrap">
            <div className="bg-white/20 backdrop-blur-sm rounded-lg px-4 py-3 text-center">
              <p className="text-2xl font-bold">12</p>
              <p className="text-xs text-purple-100">Fichiers bruts</p>
            </div>
            <div className="bg-white/20 backdrop-blur-sm rounded-lg px-4 py-3 text-center">
              <p className="text-2xl font-bold">5</p>
              <p className="text-xs text-purple-100">Transcriptions</p>
            </div>
            <div className="bg-white/20 backdrop-blur-sm rounded-lg px-4 py-3 text-center">
              <p className="text-2xl font-bold">2</p>
              <p className="text-xs text-purple-100">Projets</p>
            </div>
            <div className="bg-white/20 backdrop-blur-sm rounded-lg px-4 py-3 text-center">
              <p className="text-2xl font-bold">4</p>
              <p className="text-xs text-purple-100">Relectures</p>
            </div>
          </div>
        </div>
      </div>

      {/* Toggle Vue */}
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow mb-4 p-2">
        <div className="flex gap-2">
          <button
            onClick={() => setView('library')}
            className={`flex-1 px-4 py-3 rounded-lg text-sm font-medium transition-all duration-200 flex items-center justify-center gap-2 ${
              view === 'library'
                ? 'bg-purple-600 text-white shadow-lg'
                : 'bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600'
            }`}
          >
            <i className="fas fa-th-large"></i>
            Médiathèque
          </button>
          <button
            onClick={() => setView('flow')}
            className={`flex-1 px-4 py-3 rounded-lg text-sm font-medium transition-all duration-200 flex items-center justify-center gap-2 ${
              view === 'flow'
                ? 'bg-purple-600 text-white shadow-lg'
                : 'bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600'
            }`}
          >
            <i className="fas fa-project-diagram"></i>
            Flux Éditorial
          </button>
        </div>
      </div>

      {/* Contenu */}
      {view === 'library' ? (
        <MediaLibraryGrid 
          onOpenImport={() => setIsImportModalOpen(true)}
        />
      ) : (
        <EditorialFlow />
      )}

      {/* MODALE D'IMPORTATION (Importée depuis modals/) */}
      {isImportModalOpen && (
        <ImportModal 
          isOpen={isImportModalOpen}
          onClose={() => {
            setIsImportModalOpen(false);
            setImportType(null);
            setSelectedFiles([]);
            setUploadProgress(0);
            setIsUploading(false);
          }}
          importType={importType}
          setImportType={setImportType}
          selectedFiles={selectedFiles}
          setSelectedFiles={setSelectedFiles}
          uploadProgress={uploadProgress}
          setUploadProgress={setUploadProgress}
          isUploading={isUploading}
          setIsUploading={setIsUploading}
        />
      )}
    </div>
  );
};

// ✅ COMPOSANT GRILLE AVEC PAGINATION (12 fichiers/page)
const MediaLibraryGrid: React.FC<{ onOpenImport: () => void }> = ({ onOpenImport }) => {
  const [searchTerm, setSearchTerm] = useState("");
  const [typeFilter, setTypeFilter] = useState("Tous");
  const [dateFilter, setDateFilter] = useState("Tous");
  const [statusFilter, setStatusFilter] = useState("Tous");
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  
  // 🔑 PAGINATION - 12 fichiers par page
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 12;

  const demoFiles = [
    { id: 1, name: "audio_001.mp3", type: "audio", date: "2025-01-15", size: "5.2 MB", status: "importé" },
    { id: 2, name: "audio_002.mp3", type: "audio", date: "2025-01-15", size: "3.8 MB", status: "transcrit" },
    { id: 3, name: "scan_chapitre1.pdf", type: "pdf", date: "2025-01-14", size: "2.1 MB", status: "importé" },
    { id: 4, name: "photo_001.jpg", type: "image", date: "2025-01-14", size: "1.5 MB", status: "importé" },
    { id: 5, name: "interview_003.mp3", type: "audio", date: "2025-01-13", size: "8.4 MB", status: "transcrit" },
    { id: 6, name: "document_002.pdf", type: "pdf", date: "2025-01-13", size: "4.2 MB", status: "projet livre" },
    { id: 7, name: "audio_004.mp3", type: "audio", date: "2025-01-12", size: "6.1 MB", status: "importé" },
    { id: 8, name: "scan_chapitre2.pdf", type: "pdf", date: "2025-01-12", size: "3.3 MB", status: "transcrit" },
    { id: 9, name: "photo_002.jpg", type: "image", date: "2025-01-11", size: "2.8 MB", status: "importé" },
    { id: 10, name: "interview_005.mp3", type: "audio", date: "2025-01-11", size: "9.2 MB", status: "projet livre" },
    { id: 11, name: "document_003.pdf", type: "pdf", date: "2025-01-10", size: "5.5 MB", status: "relecture 1" },
    { id: 12, name: "audio_006.mp3", type: "audio", date: "2025-01-10", size: "7.3 MB", status: "relecture 2" },
    { id: 13, name: "scan_chapitre3.pdf", type: "pdf", date: "2025-01-09", size: "2.9 MB", status: "importé" },
    { id: 14, name: "photo_003.jpg", type: "image", date: "2025-01-09", size: "1.9 MB", status: "transcrit" },
    { id: 15, name: "interview_007.mp3", type: "audio", date: "2025-01-08", size: "8.8 MB", status: "importé" },
  ];

  // ✅ FILTRAGE
  const filteredFiles = useMemo(() => {
    return demoFiles.filter((file) => {
      const matchesSearch = file.name.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesType = typeFilter === "Tous" || file.type === typeFilter;
      const matchesStatus = statusFilter === "Tous" || file.status === statusFilter;
      
      let matchesDate = true;
      if (dateFilter === "today") {
        matchesDate = file.date === new Date().toISOString().split('T')[0];
      } else if (dateFilter === "week") {
        const weekAgo = new Date();
        weekAgo.setDate(weekAgo.getDate() - 7);
        matchesDate = new Date(file.date) >= weekAgo;
      } else if (dateFilter === "month") {
        const monthAgo = new Date();
        monthAgo.setMonth(monthAgo.getMonth() - 1);
        matchesDate = new Date(file.date) >= monthAgo;
      }
      
      return matchesSearch && matchesType && matchesStatus && matchesDate;
    });
  }, [searchTerm, typeFilter, dateFilter, statusFilter]);

  // 🔑 PAGINATION - Calcul des pages
  const totalPages = Math.ceil(filteredFiles.length / itemsPerPage);
  
  // 🔑 PAGINATION - Fichiers de la page courante
  const paginatedFiles = useMemo(() => {
    const startIndex = (currentPage - 1) * itemsPerPage;
    return filteredFiles.slice(startIndex, startIndex + itemsPerPage);
  }, [filteredFiles, currentPage, itemsPerPage]);

  // ✅ Réinitialiser la page 1 quand les filtres changent
  useMemo(() => {
    setCurrentPage(1);
  }, [searchTerm, typeFilter, dateFilter, statusFilter]);

  const getFileIcon = (type: string) => {
    switch (type) {
      case 'audio': return 'fas fa-music text-blue-500';
      case 'pdf': return 'fas fa-file-pdf text-red-500';
      case 'image': return 'fas fa-file-image text-green-500';
      default: return 'fas fa-file text-gray-500';
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'importé': return 'bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-200';
      case 'transcrit': return 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-200';
      case 'projet livre': return 'bg-purple-100 text-purple-800 dark:bg-purple-900/30 dark:text-purple-200';
      case 'relecture 1': return 'bg-amber-100 text-amber-800 dark:bg-amber-900/30 dark:text-amber-200';
      case 'relecture 2': return 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-200';
      default: return 'bg-gray-100 text-gray-800 dark:bg-gray-700 dark:text-gray-200';
    }
  };

  return (
    <div className="bg-white dark:bg-gray-800 rounded-xl shadow-lg border border-gray-200 dark:border-gray-700 overflow-hidden">
      {/* Barre d'outils */}
      <div className="bg-gradient-to-r from-gray-50 to-gray-100 dark:from-gray-700/50 dark:to-gray-700 px-6 py-4 border-b border-gray-200 dark:border-gray-700">
        <div className="flex flex-col lg:flex-row gap-4">
          {/* Recherche */}
          <div className="flex-1 relative">
            <input
              type="text"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-12 pr-4 py-3 text-base border border-gray-300 dark:border-gray-600 rounded-xl focus:outline-none focus:ring-2 focus:ring-purple-500 focus:border-transparent dark:bg-gray-700 dark:text-white transition-all duration-200"
              placeholder="🔍 Rechercher un fichier par nom..."
            />
            <i className="fas fa-search absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400"></i>
            {searchTerm && (
              <button
                onClick={() => setSearchTerm("")}
                className="absolute right-4 top-1/2 transform -translate-y-1/2 text-gray-400 hover:text-gray-600"
              >
                <i className="fas fa-times"></i>
              </button>
            )}
          </div>
          
          {/* Filtres */}
          <div className="flex gap-3 flex-wrap items-center">
            <select
              value={typeFilter}
              onChange={(e) => setTypeFilter(e.target.value)}
              className="px-4 py-3 border border-gray-300 dark:border-gray-600 rounded-xl focus:outline-none focus:ring-2 focus:ring-purple-500 dark:bg-gray-700 dark:text-white transition-all duration-200"
            >
              <option value="Tous">📁 Tous types</option>
              <option value="audio">🎵 Audio</option>
              <option value="pdf">📄 PDF</option>
              <option value="image">🖼️ Image</option>
            </select>
            
            <select
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
              className="px-4 py-3 border border-gray-300 dark:border-gray-600 rounded-xl focus:outline-none focus:ring-2 focus:ring-purple-500 dark:bg-gray-700 dark:text-white transition-all duration-200"
            >
              <option value="Tous">📊 Tous statuts</option>
              <option value="importé">📥 Importé</option>
              <option value="transcrit">✍️ Transcrit</option>
              <option value="projet livre">📖 Projet livre</option>
              <option value="relecture 1">👁️ Relecture 1</option>
              <option value="relecture 2">👁️ Relecture 2</option>
            </select>
            
            <select
              value={dateFilter}
              onChange={(e) => setDateFilter(e.target.value)}
              className="px-4 py-3 border border-gray-300 dark:border-gray-600 rounded-xl focus:outline-none focus:ring-2 focus:ring-purple-500 dark:bg-gray-700 dark:text-white transition-all duration-200"
            >
              <option value="Tous">📅 Toutes dates</option>
              <option value="today">Aujourd'hui</option>
              <option value="week">Cette semaine</option>
              <option value="month">Ce mois</option>
            </select>

            {/* Toggle Grid/List */}
            <div className="flex border border-gray-300 dark:border-gray-600 rounded-xl overflow-hidden">
              <button
                onClick={() => setViewMode('grid')}
                className={`px-3 py-3 transition-all duration-200 ${
                  viewMode === 'grid'
                    ? 'bg-purple-600 text-white'
                    : 'bg-white dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600'
                }`}
              >
                <i className="fas fa-th"></i>
              </button>
              <button
                onClick={() => setViewMode('list')}
                className={`px-3 py-3 transition-all duration-200 ${
                  viewMode === 'list'
                    ? 'bg-purple-600 text-white'
                    : 'bg-white dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600'
                }`}
              >
                <i className="fas fa-list"></i>
              </button>
            </div>
            
            {/* BOUTON IMPORTER */}
            <button 
              onClick={onOpenImport}
              className="px-6 py-3 bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-700 hover:to-indigo-700 text-white rounded-xl transition-all duration-200 flex items-center gap-2 shadow-lg hover:shadow-xl transform hover:-translate-y-0.5"
            >
              <i className="fas fa-upload"></i>
              Importer
            </button>
          </div>
        </div>
        
        {/* Résultats */}
        <div className="mt-4 flex items-center justify-between">
          <p className="text-sm text-gray-600 dark:text-gray-400">
            <strong className="text-purple-600 dark:text-purple-400">{paginatedFiles.length}</strong> fichier{paginatedFiles.length > 1 ? 's' : ''} affiché{paginatedFiles.length > 1 ? 's' : ''} sur <strong>{filteredFiles.length}</strong> filtré{filteredFiles.length > 1 ? 's' : ''}
          </p>
          {(searchTerm || typeFilter !== "Tous" || dateFilter !== "Tous" || statusFilter !== "Tous") && (
            <button
              onClick={() => {
                setSearchTerm("");
                setTypeFilter("Tous");
                setDateFilter("Tous");
                setStatusFilter("Tous");
                setCurrentPage(1);
              }}
              className="text-sm text-purple-600 dark:text-purple-400 hover:text-purple-800 dark:hover:text-purple-300 flex items-center gap-1"
            >
              <i className="fas fa-times-circle"></i>
              Réinitialiser les filtres
            </button>
          )}
        </div>
      </div>

      {/* Grille/Liste de fichiers */}
      <div className="p-6 overflow-y-auto" style={{ maxHeight: 'calc(100vh - 500px)' }}>
        {paginatedFiles.length === 0 ? (
          <div className="text-center py-16">
            <div className="inline-block p-6 bg-gray-100 dark:bg-gray-700 rounded-full mb-4">
              <i className="fas fa-search text-5xl text-gray-400"></i>
            </div>
            <p className="text-lg text-gray-600 dark:text-gray-400 font-medium mb-2">
              Aucun fichier ne correspond aux filtres
            </p>
            <p className="text-sm text-gray-500 dark:text-gray-500">
              Essayez de modifier vos critères de recherche
            </p>
          </div>
        ) : viewMode === 'grid' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
            {paginatedFiles.map((file) => (
              <FileCard key={file.id} file={file} getFileIcon={getFileIcon} getStatusColor={getStatusColor} />
            ))}
          </div>
        ) : (
          <div className="space-y-2">
            {paginatedFiles.map((file) => (
              <FileListItem key={file.id} file={file} getFileIcon={getFileIcon} getStatusColor={getStatusColor} />
            ))}
          </div>
        )}
      </div>

      {/* 🔑 PAGINATION CONTROLS */}
      {totalPages > 1 && (
        <div className="px-6 py-4 border-t border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-700/50">
          <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-4">
            <p className="text-sm text-gray-600 dark:text-gray-400">
              Page <strong className="text-purple-600 dark:text-purple-400">{currentPage}</strong> sur <strong>{totalPages}</strong> • {filteredFiles.length} résultat{filteredFiles.length > 1 ? 's' : ''}
            </p>
            
            <div className="flex items-center gap-2">
              <button
                onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                disabled={currentPage === 1}
                className="px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-100 dark:hover:bg-gray-600 transition-all duration-200 flex items-center gap-2"
              >
                <i className="fas fa-chevron-left"></i>
                <span className="hidden sm:inline">Précédent</span>
              </button>
              
              <div className="flex gap-1">
                {[...Array(Math.min(5, totalPages))].map((_, i) => {
                  const pageNum = Math.max(1, currentPage - 2) + i;
                  if (pageNum > totalPages) return null;
                  
                  return (
                    <button
                      key={pageNum}
                      onClick={() => setCurrentPage(pageNum)}
                      className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200 ${
                        currentPage === pageNum
                          ? 'bg-purple-600 text-white shadow-lg'
                          : 'bg-white dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600 border border-gray-300 dark:border-gray-600'
                      }`}
                    >
                      {pageNum}
                    </button>
                  );
                })}
              </div>
              
              {totalPages > 5 && currentPage < totalPages - 2 && (
                <span className="px-2 py-2 text-gray-500 dark:text-gray-400">...</span>
              )}
              
              {totalPages > 5 && currentPage < totalPages - 1 && (
                <button
                  onClick={() => setCurrentPage(totalPages)}
                  className="px-4 py-2 rounded-lg text-sm font-medium bg-white dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600 border border-gray-300 dark:border-gray-600 transition-all duration-200"
                >
                  {totalPages}
                </button>
              )}
              
              <button
                onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
                disabled={currentPage === totalPages}
                className="px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-100 dark:hover:bg-gray-600 transition-all duration-200 flex items-center gap-2"
              >
                <span className="hidden sm:inline">Suivant</span>
                <i className="fas fa-chevron-right"></i>
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

// ✅ COMPOSANT CARTE FICHIER
const FileCard: React.FC<{ file: any; getFileIcon: any; getStatusColor: any }> = ({ file, getFileIcon, getStatusColor }) => {
  return (
    <div className="group bg-white dark:bg-gray-700 rounded-xl border border-gray-200 dark:border-gray-600 p-4 hover:shadow-xl hover:border-purple-300 dark:hover:border-purple-500 transition-all duration-200 cursor-pointer">
      <div className="flex items-start justify-between mb-3">
        <div className="flex items-center gap-3">
          <div className="w-14 h-14 bg-gradient-to-br from-gray-100 to-gray-200 dark:from-gray-600 dark:to-gray-700 rounded-xl flex items-center justify-center group-hover:scale-110 transition-transform duration-200">
            <i className={`${getFileIcon(file.type)} text-2xl`}></i>
          </div>
          <div>
            <h3 className="font-semibold text-gray-900 dark:text-white text-sm line-clamp-1 group-hover:text-purple-600 dark:group-hover:text-purple-400 transition-colors">
              {file.name}
            </h3>
            <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">
              {file.date} • {file.size}
            </p>
          </div>
        </div>
        <button className="opacity-0 group-hover:opacity-100 transition-opacity p-2 hover:bg-gray-100 dark:hover:bg-gray-600 rounded-lg">
          <i className="fas fa-ellipsis-v text-gray-400"></i>
        </button>
      </div>
      
      <div className="flex gap-2 flex-wrap">
        <span className={`px-2.5 py-1 text-xs font-medium rounded-full capitalize ${getStatusColor(file.status)}`}>
          {file.status}
        </span>
        <span className="px-2.5 py-1 text-xs font-medium rounded-full bg-gray-100 dark:bg-gray-600 text-gray-700 dark:text-gray-300 capitalize">
          {file.type}
        </span>
      </div>

      {/* Actions au survol */}
      <div className="mt-3 pt-3 border-t border-gray-100 dark:border-gray-600 opacity-0 group-hover:opacity-100 transition-opacity flex gap-2">
        <button className="flex-1 px-3 py-1.5 text-xs bg-purple-100 dark:bg-purple-900/30 text-purple-700 dark:text-purple-300 rounded-lg hover:bg-purple-200 dark:hover:bg-purple-900/50 transition-colors">
          <i className="fas fa-eye mr-1"></i> Voir
        </button>
        <button className="flex-1 px-3 py-1.5 text-xs bg-gray-100 dark:bg-gray-600 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-200 dark:hover:bg-gray-500 transition-colors">
          <i className="fas fa-download mr-1"></i> Télécharger
        </button>
      </div>
    </div>
  );
};

// ✅ COMPOSANT LISTE FICHIER
const FileListItem: React.FC<{ file: any; getFileIcon: any; getStatusColor: any }> = ({ file, getFileIcon, getStatusColor }) => {
  return (
    <div className="group flex items-center justify-between bg-white dark:bg-gray-700 rounded-xl border border-gray-200 dark:border-gray-600 p-4 hover:shadow-lg hover:border-purple-300 dark:hover:border-purple-500 transition-all duration-200 cursor-pointer">
      <div className="flex items-center gap-4 flex-1">
        <div className="w-12 h-12 bg-gradient-to-br from-gray-100 to-gray-200 dark:from-gray-600 dark:to-gray-700 rounded-xl flex items-center justify-center">
          <i className={`${getFileIcon(file.type)} text-xl`}></i>
        </div>
        <div className="flex-1 min-w-0">
          <h3 className="font-semibold text-gray-900 dark:text-white text-sm truncate group-hover:text-purple-600 dark:group-hover:text-purple-400 transition-colors">
            {file.name}
          </h3>
          <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">
            {file.date} • {file.size}
          </p>
        </div>
      </div>
      
      <div className="flex items-center gap-3">
        <span className={`px-3 py-1 text-xs font-medium rounded-full capitalize ${getStatusColor(file.status)}`}>
          {file.status}
        </span>
        <span className="px-3 py-1 text-xs font-medium rounded-full bg-gray-100 dark:bg-gray-600 text-gray-700 dark:text-gray-300 capitalize">
          {file.type}
        </span>
        <button className="opacity-0 group-hover:opacity-100 transition-opacity p-2 hover:bg-gray-100 dark:hover:bg-gray-600 rounded-lg">
          <i className="fas fa-ellipsis-v text-gray-400"></i>
        </button>
      </div>
    </div>
  );
};

export default MediaLibrary;
